  founded_year = 1998,
  company_size = $q$10,000+ employees$q$,
  headquarters = $q$San Jose, California, USA$q$,
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Dutch$q$, $q$Chinese$q$, $q$Japanese$q$, $q$Korean$q$]::text[],
