INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Digital wallet$q$, $q$Store balances and link bank accounts or cards to send and receive money without sharing financial details directly with other parties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Online checkout button$q$, $q$Embed a recognizable PayPal payment option on websites and online stores to let customers check out quickly.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Invoicing$q$, $q$Create and send professional invoices directly to clients by email, with support for tracking payment status.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Buyer and seller protection$q$, $q$Built-in dispute resolution and protection policies designed to build trust between buyers and sellers transacting online.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Developer APIs$q$, $q$SDKs and APIs that let developers integrate PayPal checkout, payouts, and subscriptions into custom websites and applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Recurring billing$q$, $q$Set up subscription and recurring payment plans for businesses that bill customers on a regular schedule.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Multi-currency support$q$, $q$Send, receive, and accept payments in a range of currencies, useful for businesses selling to international customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Business dashboard and reporting$q$, $q$A merchant-facing dashboard showing transaction history, refunds, disputes, and basic sales reporting.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Mobile app$q$, $q$iOS and Android apps for managing balances, sending money, and tracking business transactions on the go.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Widely recognized brand that many shoppers already trust at checkout$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Free and quick to sign up for personal use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Buyer and seller protection helps build confidence in online transactions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Supports invoicing and payments across many currencies for global business$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Developer APIs make it possible to integrate checkout into custom sites and apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Transaction fees for merchants can be higher than negotiated processor rates at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Account holds or reviews can occur in certain higher-risk transaction patterns$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Currency conversion fees can apply to cross-border payments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Customer support for account issues can be slower than some businesses need$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Checkout branding is less customizable than some dedicated payment processors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Is PayPal free to use?$q$, $q$Signing up for a personal PayPal account is free. Fees generally apply to certain transactions, such as receiving business payments, currency conversion, or specific card and instant transfer options.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Can I use PayPal to accept payments as a small business?$q$, $q$Yes, PayPal offers business accounts with checkout buttons, invoicing, and merchant tools designed for online and in-person sales, with transaction fees applied per payment.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Does PayPal work internationally?$q$, $q$PayPal supports sending, receiving, and accepting payments in multiple currencies, making it a common choice for businesses and freelancers working with international clients.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$What is PayPal buyer protection?$q$, $q$Buyer protection is a policy that can help cover eligible purchases that don't arrive or don't match their description, subject to PayPal's terms and dispute process.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Can developers integrate PayPal into their own website or app?$q$, $q$Yes, PayPal provides developer APIs and SDKs that allow businesses to embed checkout, subscriptions, and payout functionality directly into custom websites and applications.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Sending money between friends and family$q$, $q$Quickly send or request money from another person using just an email address or phone number, without exchanging bank details.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Accepting payments on an online store$q$, $q$Add a PayPal checkout button to a website or e-commerce platform so customers can pay using a familiar, trusted option.$q$, $q$Online sellers and small e-commerce businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Invoicing clients for freelance work$q$, $q$Create and email invoices to clients, track payment status, and receive funds directly into a linked account.$q$, $q$Freelancers and independent consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Accepting recurring subscription payments$q$, $q$Set up recurring billing so customers are automatically charged on a regular schedule for ongoing services or memberships.$q$, $q$Subscription-based businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Personal$q$, $q$Free$q$, $q$N/A$q$, $q$["Send and receive money","Link bank accounts and cards","Mobile app access","Basic buyer protection"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Business Standard$q$, $q$Percentage plus a fixed fee per transaction$q$, $q$Usage-based$q$, $q$["Online checkout button","Invoicing tools","Merchant dashboard and reporting","Multi-currency acceptance"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Business with Developer APIs$q$, $q$Percentage plus a fixed fee per transaction$q$, $q$Usage-based$q$, $q$["Custom checkout integration via API","Recurring billing and subscriptions","Payouts for platforms and marketplaces","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Negotiated transaction rates","Dedicated account support","Advanced fraud tools","Custom integration options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PayPal is one of the best-known digital payment platforms in the world, giving individuals and businesses a way to send, receive, and manage money online without sharing bank details directly with the other party. It works as both a personal wallet and a merchant payment processor, connecting to bank accounts, debit cards, and credit cards so users can move money domestically and across borders in a wide range of currencies.$q$, $q$Founded in 1998 and headquartered in San Jose, California, PayPal helped popularize online payments during the early growth of e-commerce and has since expanded into a broad fintech company. Its checkout button became a familiar sight on online stores, and its buyer and seller protection policies helped build trust between strangers transacting over the internet before that kind of trust was common.$q$, $q$Today PayPal serves millions of consumers and merchants through a consumer app, a business dashboard, invoicing tools, and developer APIs that let companies embed PayPal checkout directly into their own websites and apps. It sits alongside cards and bank transfers as one of the standard ways people pay and get paid online, from splitting a bill with a friend to running a full e-commerce storefront.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$who-paypal-is-for$q$, $q$Who PayPal Is For$q$, 2, ARRAY[$q$Everyday consumers who want a quick, familiar way to pay online are a natural fit for PayPal. It lets them check out on many websites without re-entering card numbers, and its buyer protection can offer peace of mind for purchases from unfamiliar sellers.$q$, $q$Online sellers, small business owners, and marketplace merchants also rely heavily on PayPal because customers already recognize and trust the brand at checkout. Accepting PayPal alongside cards can reduce cart abandonment for shoppers who prefer not to enter card details on every new site.$q$, $q$Freelancers, consultants, and service-based businesses that need to invoice clients, especially internationally, often choose PayPal for its straightforward invoicing tools and ability to accept payments in multiple currencies without needing a full merchant banking setup.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses with very high transaction volumes or thin margins may find PayPal's standard per-transaction fees add up faster than a negotiated payment processor rate, making a dedicated merchant account potentially more cost-effective at scale.$q$, $q$Merchants operating in industries that payment processors commonly flag as higher risk, such as certain subscription models, digital goods, or dispute-prone categories, may run into account holds or reviews that are frustrating if fast, uninterrupted cash flow is critical.$q$, $q$Companies that need a fully custom, tightly controlled checkout experience with minimal reliance on a third-party brand at the point of payment may prefer building directly on a processor that offers more flexible, white-labeled integration options.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, PayPal offers a digital wallet for sending and receiving money, an online checkout button that can be added to websites, and invoicing tools for billing clients directly by email. Buyer and seller protection programs are built into transactions to help resolve disputes.$q$, $q$For businesses, PayPal provides a merchant dashboard with transaction history and reporting, developer APIs and SDKs for integrating payments into custom websites and apps, support for recurring billing and subscriptions, and multi-currency acceptance for selling to international customers.$q$, $q$PayPal also offers physical and virtual card products in some markets, in-person payment options for sellers who need to take payments face to face, and mobile apps that let both consumers and business owners manage payments, transfers, and account activity from a phone.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('309c46ca-1066-4ecc-be4d-d5984e2cd67e', $q$the-paypal-experience$q$, $q$The PayPal Experience$q$, 2, ARRAY[$q$Getting started with PayPal is simple: users sign up with an email address, link a bank account or card, and can begin sending or receiving money almost immediately. Businesses can set up a merchant profile to start accepting checkout payments on their own site or through supported e-commerce platforms.$q$, $q$For everyday use, the checkout experience is designed to be fast and familiar, letting returning customers pay with a few clicks instead of re-entering payment details. The mobile app mirrors much of this simplicity, showing recent transactions, balances, and quick actions for sending or requesting money.$q$, $q$On the business side, the dashboard provides visibility into sales, refunds, and disputes, along with invoicing and reporting tools that help small business owners keep track of cash flow without needing separate accounting software for basic payment tracking.$q$]::text[], 4);
