INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$PDF Annotation$q$, $q$Highlight, underline, strike through, add sticky notes, and draw freehand or with Apple Pencil directly on any page.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Text and Image Editing$q$, $q$Edit existing text, images, and page layout inside a PDF instead of only layering comments on top of it.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Fillable Forms$q$, $q$Fill out and build interactive forms with text fields, checkboxes, dropdowns, and signature blocks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$E-Signatures$q$, $q$Sign documents yourself or request signatures from other people without leaving the app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Merge and Organize Pages$q$, $q$Combine multiple files, split large documents, and reorder, rotate, or delete individual pages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Optical Character Recognition (OCR)$q$, $q$Turn scanned paper documents into searchable, selectable, and editable text.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Cloud Storage Integration$q$, $q$Connect iCloud Drive, Dropbox, Google Drive, and other services to keep files synced across devices.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Apple Pencil Support$q$, $q$Take handwritten notes and add ink annotations on iPad with smooth, low-latency, palm-rejecting input.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Split View and Multitasking$q$, $q$Work with a PDF side by side with another app on iPad for referencing content while writing or emailing.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Redaction and Page Security$q$, $q$Permanently remove sensitive content from a page and protect documents with passwords.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Feels like a native Apple app with fast performance, clean design, and full Apple Pencil support on iPad$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Editing tools go beyond simple annotation, letting users change actual text and images inside a PDF$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Built-in e-signature and form-filling tools remove the need for a separate signing app for everyday paperwork$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$A free tier covers basic viewing and light annotation, so people can try the core experience before paying$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Regular updates keep it tightly aligned with new iOS, iPadOS, and macOS features shortly after Apple releases them$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$No native Windows or Android app, which is a dealbreaker for teams that need one tool across every platform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Advanced editing, forms, and e-signature features sit behind a paid Pro plan, so the free version is fairly limited$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Lacks some enterprise-grade features like granular team permissions and centralized admin management found in bigger platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Editing complex, heavily formatted PDFs can occasionally introduce small layout shifts compared with the original file$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Pricing has shifted toward subscriptions over time, which can feel less appealing to users who prefer a single upfront purchase$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Is PDF Expert free to use?$q$, $q$PDF Expert offers a free version for viewing and basic annotation, with a paid Pro subscription that unlocks editing, forms, e-signatures, and other advanced tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Does PDF Expert work on Windows or Android?$q$, $q$No. PDF Expert is built specifically for Apple devices and runs on Mac, iPhone, and iPad; there is no native Windows or Android app.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Can I edit the actual text in a PDF, not just add annotations?$q$, $q$Yes, PDF Expert lets you edit existing text, images, and page layout directly, in addition to standard markup and comment tools.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Does PDF Expert support e-signatures?$q$, $q$Yes, you can sign documents yourself and request signatures from others without leaving the app.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Does PDF Expert sync across my Apple devices?$q$, $q$Yes, through iCloud and other cloud storage integrations, documents and edits can carry over between iPhone, iPad, and Mac.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Reviewing and Signing Contracts on the Go$q$, $q$Open, mark up, and e-sign contracts and agreements directly from an iPhone or iPad without printing or scanning anything.$q$, $q$Freelancers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Studying and Annotating PDF Textbooks$q$, $q$Highlight passages, add handwritten notes with Apple Pencil, and quickly navigate long academic readings.$q$, $q$Students and academics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Digitizing and Organizing Scanned Paperwork$q$, $q$Use OCR to make scanned paper documents searchable, then merge, split, and organize them into clean files.$q$, $q$Real estate agents, legal assistants, and administrative professionals$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Filling Out and Managing Recurring PDF Forms$q$, $q$Fill out intake forms, applications, and other recurring paperwork and reuse the same layouts across clients.$q$, $q$Small teams that handle repetitive form-based paperwork$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["View and open PDF files","Basic annotation such as highlights and notes","Access files from connected cloud storage","Limited editing capabilities"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Pro Monthly$q$, $q$$9.99/month$q$, $q$Monthly$q$, $q$["Full text and image editing","Unlimited e-signatures","Form filling and creation","OCR for scanned documents"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$Pro Annual$q$, $q$$79.99/year$q$, $q$Annual$q$, $q$["Full text and image editing","Unlimited e-signatures","Form filling and creation","OCR for scanned documents","Lower effective monthly cost than the monthly plan"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PDF Expert is a PDF reader, editor, and annotation app built by Readdle, designed specifically for the Apple ecosystem of Mac, iPhone, and iPad. Rather than treating PDFs as static, uneditable files, PDF Expert lets people open, mark up, edit, sign, and organize documents directly on their devices, positioning itself as a lighter, more approachable alternative to legacy desktop PDF suites that were originally built for enterprise IT departments rather than everyday users.$q$, $q$The app grew out of Readdle's early work on mobile productivity tools and has been refined over more than a decade to take advantage of native Apple features such as Apple Pencil input, Files app integration, iCloud syncing, and Split View multitasking on iPad. That native-first philosophy runs through the product's design, its update cadence, and how it is positioned against both Apple's built-in Preview app and larger, more expensive competitors.$q$, $q$Today PDF Expert covers most of the core jobs people need from a PDF tool in one place: viewing and annotating, editing text and images, filling and creating forms, merging and splitting files, applying e-signatures, and running optical character recognition on scanned documents. It is aimed squarely at individuals, freelancers, and small teams who want capable, everyday PDF editing without committing to a full enterprise document-management platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$who-pdf-expert-is-for$q$, $q$Who PDF Expert Is For$q$, 2, ARRAY[$q$PDF Expert is built for people who already live inside the Apple ecosystem and want their PDF workflow to feel native rather than bolted on top of a browser tab or a clunky cross-platform port. Mac, iPhone, and iPad users who regularly review contracts, sign forms, mark up drafts, or read PDF textbooks tend to find the interface immediately familiar and fast to pick up on day one.$q$, $q$Students and academics benefit from its annotation set, since highlighting passages, adding handwritten notes with Apple Pencil, and jumping quickly through long readings are all handled smoothly. Freelancers, consultants, and small business owners who need to sign and send contracts, invoices, and forms without adopting a full document-management system also fit the product well, since most of what they need lives in a single lightweight app.$q$, $q$Professionals in fields like real estate, law, education, and consulting who handle a steady stream of PDF paperwork, but do not need heavyweight collaboration, compliance certifications, or team-wide governance features, get most of what they need from a single one-time purchase or an affordable subscription rather than negotiating a large enterprise document-platform contract.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$PDF Expert is not the right fit for organizations standing on Windows or Android, since the app is built exclusively for macOS, iOS, and iPadOS with no native client for those platforms. Teams that need one consistent PDF tool across every employee's device, regardless of operating system, will run into a compatibility gap immediately and should look elsewhere for a cross-platform standard.$q$, $q$Businesses that depend on deep integration with enterprise content-management systems, strict e-signature compliance certifications, or advanced redaction and Bates-numbering workflows common in legal and litigation support may find PDF Expert too lightweight for their requirements. Heavy Adobe Acrobat shops with established macros, plug-ins, and long-standing internal processes will also face friction when trying to switch their entire workflow over.$q$, $q$Large organizations that need centralized admin consoles, granular per-seat permission management, and detailed audit trails across dozens or hundreds of users may find the app's individual and small-team orientation limiting compared with enterprise-grade document platforms built around shared governance and IT-managed rollouts rather than personal productivity on a handful of devices.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, PDF Expert lets people annotate documents with highlights, underlines, sticky notes, freehand drawing, and Apple Pencil ink, then edit the underlying text, images, and page layout directly rather than only stacking markup on top of a locked file. Editing feels closer to working in a word processor than fighting with a read-only viewer.$q$, $q$Form tools let users fill out and build fillable PDF forms with text fields, checkboxes, and signature blocks, while built-in e-signature support covers both signing documents and requesting signatures from other people without leaving the app. Page-management tools such as merging multiple files, splitting large documents, reordering, rotating, and deleting pages round out everyday document handling.$q$, $q$PDF Expert also includes optical character recognition to make scanned paper documents searchable and editable, and it integrates with cloud services like iCloud Drive, Dropbox, and Google Drive so files stay in sync across devices. On iPad, Split View and drag-and-drop let people reference a PDF alongside another app while taking notes or composing an email.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1f11dc1a-4647-48d8-94d1-00190d730c59', $q$the-pdf-expert-experience$q$, $q$The PDF Expert Experience$q$, 2, ARRAY[$q$Using PDF Expert feels closer to using a well-designed native Apple app than a converted desktop utility ported over from another platform. Menus are trimmed down, gestures handle most navigation, and the toolbar adapts to whichever task, whether annotating, editing, or filling a form, a person happens to be doing at that moment.$q$, $q$On iPad, Apple Pencil support is a genuine highlight of the experience, letting people write directly on a page the way they would on paper, complete with palm rejection and smooth, low-latency ink rendering. On Mac, the desktop layout keeps the document front and center while editing and annotation tools stay one click away in a side panel.$q$, $q$Because the app is tuned specifically for Apple hardware rather than built as a generic cross-platform wrapper, performance stays snappy even with long, image-heavy PDFs, and features like Handoff and iCloud sync mean a document opened on iPhone can be picked up moments later on Mac without any extra setup, which is where the platform-native approach pays off in daily use.$q$]::text[], 4);
