INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Online PDF Editor$q$, $q$Add, edit, or remove text and images directly on top of an existing PDF from within the browser, with no software to install.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Form Filler$q$, $q$Complete existing fillable PDF forms by typing directly into form fields, checkboxes, and signature areas.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Form Builder$q$, $q$Turn a static PDF into an interactive form by adding text fields, checkboxes, radio buttons, and dropdowns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Annotation Tools$q$, $q$Highlight text, add sticky notes and comments, draw freehand, and mark up documents for review.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Page Management$q$, $q$Merge multiple PDFs, insert blank or new pages, and delete or reorder existing pages within a document.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Redaction and Whiteout$q$, $q$Cover or blank out sensitive sections of a page before sharing or printing a document.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$PDF and Image Conversion$q$, $q$Convert PDF pages to image files and convert images into new PDF documents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Password Protection$q$, $q$Secure a finished PDF with a password so only intended recipients can open or edit it.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Desktop Application$q$, $q$An installable desktop version of PDFescape for editing PDFs offline outside of the browser.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Form Templates$q$, $q$Start form-building faster with ready-made templates for common document and form layouts.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Generous free tier that requires no account creation or credit card to start editing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Runs entirely in the browser, so it works across Windows, macOS, and shared computers alike$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Simple, focused toolset that is easy to pick up for occasional, everyday PDF tasks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Low-cost Premium and Desktop upgrades compared to many full-featured PDF suites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Solid form-filling and form-building tools for handling routine paperwork$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free tier includes ads and imposes file size, page count, and daily usage limits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Interface feels dated next to newer, more polished PDF editors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$No built-in OCR for making scanned documents searchable or editable$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Not designed for team collaboration, shared review workflows, or audit trails$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Lacks batch processing for editing or converting large numbers of files at once$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Is PDFescape actually free to use?$q$, $q$Yes, the core web-based editor is free with no account or credit card required, though it shows ads and enforces limits on file size and page count. Paid Premium and Desktop tiers remove those restrictions for a fee.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Do I need to create an account to edit a PDF?$q$, $q$No, you can upload a document and start editing right away without registering. Creating a free account simply lets you save documents to revisit later.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Can PDFescape create fillable forms from a regular PDF?$q$, $q$Yes, its form-builder tools let you add text fields, checkboxes, radio buttons, and signature areas to an existing static PDF to turn it into a fillable form.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Is there a desktop version of PDFescape?$q$, $q$Yes, PDFescape offers an installable Desktop application as a paid option for users who want to edit PDFs offline without a browser or internet connection.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Does PDFescape support OCR for scanned documents?$q$, $q$No, PDFescape does not include OCR text recognition, so scanned image-based PDFs cannot be made searchable or text-editable within the tool.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Filling out job and government applications$q$, $q$Job seekers and individuals can quickly complete fillable PDF applications, tax forms, or benefits paperwork directly in the browser without printing and scanning.$q$, $q$Individuals and job seekers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Drafting and marking up simple contracts$q$, $q$Freelancers and small business owners can add text, signature fields, and annotations to straightforward contracts and agreements before sending them out.$q$, $q$Freelancers and small business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Annotating study materials$q$, $q$Students can highlight passages, add sticky notes, and mark up lecture slides or readings distributed as PDFs, all without installing extra software on a shared or school computer.$q$, $q$Students$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Processing routine client paperwork$q$, $q$Real estate agents, tax preparers, and administrative staff can fill out standard disclosure forms or intake paperwork and merge supporting documents into one file.$q$, $q$Real estate and administrative professionals$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Browser-based PDF editing and annotation","Form filling and basic form building","Page merging, reordering, and deletion","Ad-supported with file size and page limits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Premium$q$, $q$Low monthly fee (see pdfescape.com for current pricing)$q$, $q$monthly$q$, $q$["Ad-free editing experience","Higher file size and page count limits","Full access to editing, annotation, and form tools","Priority processing for uploads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$Desktop$q$, $q$One-time purchase (see pdfescape.com for current pricing)$q$, $q$one-time$q$, $q$["Installable application for offline use","No internet connection required to edit","Same core editing and form tools as the web version","No ads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PDFescape is a browser-based PDF editor and form filler built by Red Software that lets anyone open, edit, and annotate PDF documents without installing desktop software. It runs entirely inside a web browser, which makes it accessible from almost any computer, whether the user is on Windows, macOS, or a shared machine where installing new applications is not an option. The core promise is simplicity: upload a file, make changes, and download or share the result within minutes.$q$, $q$At its heart, PDFescape focuses on the everyday tasks people actually need from a PDF tool rather than trying to replicate every feature of a full desktop publishing suite. Users can fill out forms, add text and images, insert checkboxes and signature fields, highlight or redact content, merge and reorder pages, and convert between PDF and image formats. This narrower focus keeps the interface approachable for people who only touch a PDF editor occasionally.$q$, $q$The free web-based version has been the product's calling card for years, offering a genuinely usable editor without a credit card requirement or a hard trial expiration. Paid Premium and Desktop tiers exist for people who edit PDFs often enough to want fewer limits, an ad-free interface, or offline access, but the free tier remains functional on its own for lightweight, occasional editing needs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$who-pdfescape-is-for$q$, $q$Who PDFescape Is For$q$, 2, ARRAY[$q$PDFescape suits individuals and small businesses who need to edit or fill out PDFs occasionally rather than as a daily, high-volume workflow. Students annotating course readings, job seekers filling out application forms, freelancers marking up a contract, or homeowners completing a government form all fit the profile of a typical PDFescape user. The tool asks for no account and no software installation, which lowers the barrier for anyone who just needs to get a single document done.$q$, $q$Small offices and solo professionals who need basic form-filling and light editing, but do not want to pay for a full document-management suite, are also a strong fit. Real estate agents completing standard disclosure forms, tax preparers filling client paperwork, and administrative staff processing routine paperwork can accomplish most of what they need inside the free or Premium tier without learning a complex application.$q$, $q$People who value working entirely in the browser, across different computers and operating systems, without worrying about license portability, will also appreciate PDFescape. Because it runs online, a user can start editing on one machine and pick up the same account or file on another, which is convenient for anyone who moves between a work computer, a home computer, or a public library terminal.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need enterprise-grade document management, granular team permissions, audit trails, or deep integrations with content management and e-signature platforms will find PDFescape's feature set too limited. It is built around single-document, single-user editing sessions rather than collaborative review workflows or automated document pipelines, so teams with those needs should look toward a more full-featured platform.$q$, $q$Users who need advanced PDF capabilities such as OCR text recognition on scanned documents, batch processing of large numbers of files, complex layout re-flowing, or heavy-duty redaction with compliance guarantees will likely outgrow PDFescape quickly. The free tier in particular imposes file size and page limits that make it impractical for large scanned books, oversized engineering drawings, or bulk operations.$q$, $q$Anyone who is sensitive to a dated or ad-supported interface on the free tier, or who needs polished, brand-consistent output for client-facing design work, may prefer a more modern editor. PDFescape's interface is functional but has not been redesigned as aggressively as some newer competitors, so users who prioritize visual polish or a slicker editing experience over price should weigh other options.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of PDFescape is its in-browser PDF editor, which allows users to add or modify text, insert images, draw shapes, and rearrange pages directly on top of an existing PDF. Alongside editing, the form-filling and form-building tools let users complete existing fillable forms or turn a static PDF into one with text fields, checkboxes, radio buttons, and signature areas, which is useful for anyone who regularly distributes forms to be filled out by others.$q$, $q$Annotation tools cover highlighting, sticky notes, freehand drawing, and whiteout or redaction-style boxes for covering sensitive content, while page-level tools support merging multiple PDFs, deleting or reordering pages, and inserting blank or new pages. PDFescape also handles basic conversions, turning PDFs into images and images into PDFs, along with password protection for restricting access to a finished document.$q$, $q$Beyond the free web editor, PDFescape offers a Desktop application for users who want offline access, and a Premium web tier that removes ads and raises the size and page limits imposed on free users. Cloud storage connections to common services and straightforward saving and download options round out the feature set, keeping the emphasis on practical, everyday PDF tasks rather than specialized enterprise workflows.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', $q$the-pdfescape-experience$q$, $q$The PDFescape Experience$q$, 2, ARRAY[$q$Using PDFescape typically starts on its homepage, where a user uploads a PDF or starts a new blank document and is dropped straight into an editing canvas with a toolbar of common actions along the top or side. There is no signup wall blocking basic editing, so a first-time visitor can be making changes to a document within seconds of arriving on the site.$q$, $q$The editing canvas itself favors function over flash: tools are laid out in fairly traditional toolbar rows, and most actions such as adding a text box, inserting a signature, or highlighting a passage take just a click and a drag. This keeps the learning curve shallow for people who only need the editor a few times a year and do not want to relearn a complex interface each time.$q$, $q$On the free tier, users will notice occasional advertising and limits on file size, page count, and daily usage, which is the trade-off for not paying anything. Upgrading to Premium removes the ads and loosens those limits, while the Desktop app extends the same core editing experience to an installed, offline application for users who prefer working outside the browser or need to edit without an internet connection.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e66e1448-1366-4bae-8a4e-3bcd643199a5', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Real-time web search synthesis$q$, $q$Combines live web retrieval with language model reasoning to generate current, conversational answers instead of static, training-data-only responses.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Inline source citations$q$, $q$Every answer includes numbered, clickable citations linking directly to the original web pages, articles, or documents used to generate the response.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Focused search modes$q$, $q$Lets users narrow queries to specific domains such as academic papers, recent news, or particular websites for more targeted results.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$File and image analysis$q$, $q$Accepts uploaded documents and images so users can ask questions directly about their own content alongside web-sourced information.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Discover feed$q$, $q$Surfaces trending topics and curated stories in a browsable feed, helping users find noteworthy information without typing a query first.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Shareable research pages$q$, $q$Converts a research thread into a structured, shareable page that can be revisited or sent to collaborators.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Multi-model access for subscribers$q$, $q$Pro users can choose among several advanced underlying language models depending on the type of question or task at hand.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Cross-platform apps$q$, $q$Native mobile apps and a browser extension bring the same sourced-answer experience to phones, tablets, and everyday browsing.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Developer API$q$, $q$Provides programmatic access to Perplexity's search and answer capabilities for teams building retrieval-augmented features into their own products.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Answers include clear, clickable citations that make fact-checking fast and straightforward$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Pulls in current, real-time information rather than relying solely on static training data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Clean, conversational interface that is easy for non-technical users to pick up quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Focused search modes and file upload support add flexibility beyond generic chat$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Available across web, mobile, and browser extension for consistent cross-device use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Synthesized answers can still misrepresent nuance from source material, so verification is still needed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Less suited to open-ended creative writing or long-form coding assistance than dedicated tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Requires an internet connection, making it unsuitable for offline or air-gapped environments$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Advanced models and higher usage limits are locked behind the paid Pro tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Depth of niche or highly specialized sources can vary depending on what is publicly indexed$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Is Perplexity free to use?$q$, $q$Yes, Perplexity offers a free tier with a daily allowance of searches using its standard model. A paid Pro subscription unlocks higher usage limits, access to more advanced models, and additional research tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$How does Perplexity differ from a traditional search engine?$q$, $q$Instead of returning a list of links, Perplexity synthesizes information from multiple sources into a direct, readable answer with inline citations, so users get a summarized response while still being able to verify sources.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Can I trust the answers Perplexity gives me?$q$, $q$Citations let you check each claim against its original source, which improves transparency, but the synthesized text can still contain errors or misinterpretations, so critical information should always be verified independently.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Does Perplexity have a mobile app?$q$, $q$Yes, Perplexity offers native apps for mobile devices in addition to its website and browser extension, providing a consistent sourced-answer experience across platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Can developers integrate Perplexity into their own products?$q$, $q$Yes, Perplexity offers an API that lets developers add its search and answer synthesis capabilities into external applications and workflows.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Academic research and literature review$q$, $q$Quickly gather and cross-reference sourced information on a topic, using citations to trace claims back to original papers or articles.$q$, $q$Students and academic researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Market and competitive research$q$, $q$Compile current, sourced summaries of industry trends, competitor news, and market data without manually visiting dozens of sites.$q$, $q$Analysts and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$News summarization and fact-checking$q$, $q$Get concise, cited summaries of breaking or recent stories to verify claims quickly before writing or reporting on them.$q$, $q$Journalists and content creators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Custom search integration$q$, $q$Embed sourced, synthesized answers into an internal tool or customer-facing product using the Perplexity API.$q$, $q$Developers and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited daily searches with the standard model","Real-time web search with inline citations","Access to web, mobile, and browser extension"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Pro$q$, $q$$20/month$q$, $q$Monthly or annual$q$, $q$["Significantly higher usage limits","Access to multiple advanced underlying models","File and image upload analysis","Extended reasoning for complex, multi-step questions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Enterprise$q$, $q$Custom$q$, $q$Contact for pricing$q$, $q$["Team collaboration and admin controls","Enhanced data privacy and security options","Centralized billing for organizations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Perplexity is an AI-powered answer engine that blends large language models with live web search to produce direct, conversational answers instead of the traditional ten blue links. When a user asks a question, Perplexity retrieves relevant sources in real time, synthesizes the information, and returns a concise answer with inline citations that link back to the original pages, letting users verify claims instantly.$q$, $q$The product launched in 2022 and quickly differentiated itself from both classic search engines and standalone chatbots by treating sourcing as a first-class feature rather than an afterthought. Every answer is accompanied by numbered references, and users can click through to read the underlying articles, reports, or forum posts that informed the response, which builds a level of trust that plain generative chat tools often lack.$q$, $q$Beyond the core search experience, Perplexity has grown into a broader research and discovery platform, offering focused search modes, file and image analysis, a discover feed of trending topics, and tools for creating shareable pages from research sessions. It is available as a website, browser extension, and native mobile apps, and it supports voice input and multiple underlying model choices for paying subscribers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$who-perplexity-is-for$q$, $q$Who Perplexity Is For$q$, 2, ARRAY[$q$Perplexity is well suited to students, researchers, and analysts who need to quickly gather and cross-reference information from multiple sources. Because every answer comes with citations, it works especially well for tasks like literature reviews, market scans, and fact-checking, where knowing where a claim came from matters as much as the claim itself.$q$, $q$Knowledge workers who spend a lot of time searching, such as journalists, consultants, product managers, and marketers, tend to get significant value from Perplexity's ability to compress many searches into a single conversational query. Its focused modes for academic papers, and its ability to summarize recent news, make it a practical daily driver for people who need current, sourced information rather than static training-data answers.$q$, $q$Curious general users who simply want faster, more trustworthy answers than a standard search engine also benefit, particularly if they are comfortable reading synthesized summaries alongside source links. Developers and technical teams can additionally use the Perplexity API to build search and retrieval-augmented features into their own products.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users who need airtight guarantees of factual accuracy for high-stakes decisions, such as legal filings or medical diagnoses, should treat Perplexity as a starting point rather than a final authority, since any AI-generated synthesis can still misinterpret or overstate what a source actually says. Professionals in these fields should always verify critical claims against the original cited material.$q$, $q$People who primarily want a creative writing partner, a long-form coding assistant, or a general-purpose conversational companion may find Perplexity's search-first design less flexible than dedicated chat assistants, since its strength is retrieval and synthesis rather than open-ended creative or coding collaboration.$q$, $q$Organizations with strict data residency, offline-access, or air-gapped environment requirements may also find Perplexity a poor fit, since its core value depends on live internet connectivity and cloud-based processing. Budget-conscious users who rarely need sourced, up-to-date answers may not find enough incremental value over free web search to justify a paid subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Perplexity performs real-time web retrieval paired with large language model synthesis, so answers reflect current events and recent publications rather than only a model's static training data. Inline numbered citations accompany every answer, letting users trace each claim back to its source with a single click, which supports transparency and quick fact-checking.$q$, $q$Focused search modes let users narrow results to academic sources, specific domains, or particular content types, while file, image, and document upload support allows the assistant to answer questions about uploaded material directly. A discover feed surfaces trending topics and curated stories, and users can save research threads as shareable, structured pages for later reference or collaboration.$q$, $q$Paid subscribers gain access to more advanced underlying models, higher usage limits, and additional tools such as extended reasoning modes for complex, multi-step questions. Native apps for mobile devices and a browser extension bring the same sourced-answer experience to on-the-go searching, and an API tier allows developers to integrate Perplexity's search and answer capabilities into external applications.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$the-perplexity-experience$q$, $q$The Perplexity Experience$q$, 2, ARRAY[$q$Using Perplexity feels closer to a research conversation than a traditional search session. The interface is clean and minimal, centered on a single search box, and answers appear as readable paragraphs with citation markers woven naturally into the text rather than as a separate list of links tacked on at the end.$q$, $q$Follow-up questions are handled conversationally, so users can refine or expand on an initial answer without restarting their search, and the system keeps track of context from earlier in the thread. Suggested related questions appear after each response, which helps guide deeper exploration of a topic without requiring the user to formulate every next query themselves.$q$, $q$Overall, the experience emphasizes speed, transparency, and trust: answers load quickly, sources are always visible and clickable, and the interface avoids clutter in favor of getting users a usable answer with minimal friction. For anyone accustomed to sifting through search results manually, the shift to synthesized, sourced answers can feel like a meaningful step up in efficiency.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
