INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$AI Sales Assistant$q$, $q$Get suggested next actions and performance insights based on pipeline activity and historical patterns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Email Sync & Templates$q$, $q$Send, receive, and track emails directly from Pipedrive using reusable templates and open tracking.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Sales Reporting & Forecasting$q$, $q$Visual dashboards and reports show conversion rates, deal velocity, and revenue forecasts by rep or team.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Marketplace & Integrations$q$, $q$Connect Pipedrive to tools like Google Workspace, Slack, Zoom, and Zapier through a large app marketplace.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Mobile Apps$q$, $q$Manage deals, log activities, and access contact data on the go with native iOS and Android apps.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Lead Capture Tools$q$, $q$Optional add-ons provide web forms, chatbots, and live chat to route new leads directly into the pipeline.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Custom Fields & Multiple Pipelines$q$, $q$Configure custom fields and run separate pipelines for different products, regions, or sales processes.$q$, 9);
