INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Add-ons like advanced lead capture tools carry additional cost$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Does Pipedrive have a free plan?$q$, $q$No, Pipedrive does not offer a permanent free plan. It provides a free trial period so teams can evaluate the platform before choosing a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$What is Pipedrive best used for?$q$, $q$Pipedrive is best used for visual sales pipeline management, helping teams track deals, activities, and follow-ups through customizable pipeline stages.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Does Pipedrive integrate with email?$q$, $q$Yes, Pipedrive syncs with email providers like Gmail and Outlook so reps can send, receive, and track messages directly within the CRM.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Can Pipedrive scale to enterprise use?$q$, $q$Pipedrive can support growing sales organizations, but very large enterprises with highly complex, multi-department workflows may eventually outgrow it.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Is there a Pipedrive mobile app?$q$, $q$Yes, Pipedrive offers native mobile apps for iOS and Android so reps can manage deals and activities away from their desks.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Early-stage startup sales tracking$q$, $q$A founder-led sales team uses Pipedrive's visual pipeline to move a small number of high-touch deals through stages without heavy CRM overhead.$q$, $q$Early-stage startup founders and small sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Real estate lead and deal management$q$, $q$Agents track property leads and transactions through custom pipeline stages, logging calls and follow-ups tied to each listing or client.$q$, $q$Real estate agencies and independent agents$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Agency client pipeline management$q$, $q$Marketing and creative agencies track prospective client engagements from pitch to signed contract using dedicated pipelines per service line.$q$, $q$Marketing and creative agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Outbound B2B sales with automation$q$, $q$A B2B sales team automates follow-up tasks and email sequences as deals move through stages, using AI suggestions to prioritize outreach.$q$, $q$B2B SaaS and outbound sales teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Essential$q$, $q$From $14/seat/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Visual sales pipeline","Activity and deal management","Custom fields","Basic reporting","Email integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Advanced$q$, $q$From $34/seat/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Everything in Essential","Full email sync and templates","Workflow automation builder","Meeting scheduling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Professional$q$, $q$From $49/seat/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Everything in Advanced","Revenue forecasting","Advanced reporting and insights","Team performance dashboards"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$Enterprise$q$, $q$From $99/seat/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Everything in Professional","Enhanced security controls","Unlimited automations and permission sets","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pipedrive is a customer relationship management platform built specifically around the concept of a visual sales pipeline. Founded in 2010 in Tallinn, Estonia, the company set out to build a CRM designed by salespeople rather than software engineers, focusing on the day-to-day mechanics of moving deals through stages instead of generic contact management.$q$, $q$At its core, Pipedrive organizes work around deals, activities, and pipeline stages displayed as draggable cards on a kanban-style board. The philosophy is activity-based selling: instead of just logging what happened, the system nudges reps toward the next action that will move a deal forward, which has made it popular with teams that want structure without heavy administrative overhead.$q$, $q$Within the broader CRM market, Pipedrive is generally positioned as a lightweight, sales-first alternative to larger suites like Salesforce or HubSpot. It has grown a large ecosystem of integrations and add-ons over the years, but it has stayed focused on sales pipeline and deal tracking as its primary use case rather than trying to be an all-in-one business platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$who-pipedrive-is-for$q$, $q$Who Pipedrive Is For$q$, 2, ARRAY[$q$Pipedrive is best suited to small and mid-sized sales teams that need a clear, visual way to track deals without a long implementation process. Founders, sales managers, and individual reps who want to see exactly where every deal stands, and what needs to happen next, tend to get value from it quickly.$q$, $q$It fits particularly well for sales-led organizations where the pipeline itself is the primary workflow, such as B2B SaaS companies, agencies, consultancies, and real estate teams that manage a steady flow of leads and opportunities through defined stages. Teams moving off spreadsheets often find the transition to Pipedrive relatively painless.$q$, $q$It also suits businesses that want CRM functionality without dedicating an administrator to configure it full time. The interface is approachable enough for non-technical users to set up pipelines, custom fields, and automations largely on their own, which makes it attractive to smaller companies without a dedicated RevOps or systems team.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-department workflows, extensive approval chains, or highly customized data models may find Pipedrive's simplicity limiting compared to more configurable platforms like Salesforce, which are built to model arbitrarily complex business processes.$q$, $q$Organizations that need deep, native marketing automation, customer support ticketing, or advanced multi-channel campaign management as a core part of their CRM should also look elsewhere, or budget for third-party integrations. Pipedrive covers sales pipeline management well but treats marketing and service functions as adjacent, often add-on, capabilities rather than built-in strengths.$q$, $q$Teams hoping for a permanent free tier will also be disappointed, since Pipedrive only offers a time-limited free trial rather than a free-forever plan. Companies with very tight budgets that need to run a CRM indefinitely at no cost may prefer a tool that offers a genuinely free plan instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of Pipedrive is its visual pipeline, where deals appear as cards that reps drag between customizable stages. Teams can run multiple pipelines for different products, regions, or sales motions, and each deal carries associated contacts, notes, files, and a running activity history.$q$, $q$Automation and AI features sit alongside the pipeline to reduce manual work: workflow automation can move deals, send emails, or create tasks based on triggers, while the built-in Sales Assistant surfaces suggested actions and performance insights based on account activity. Email sync lets reps send and track messages from within the CRM using templates and open tracking.$q$, $q$Beyond the pipeline itself, Pipedrive offers sales reporting and forecasting dashboards, a mobile app for iOS and Android, and a marketplace of integrations covering tools like Google Workspace, Slack, Zoom, and Zapier. Optional add-ons such as LeadBooster extend the platform with chatbots, web forms, and live chat for lead capture.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9f9ecc1-a538-4c7f-b987-67a12f749876', $q$the-pipedrive-experience$q$, $q$The Pipedrive Experience$q$, 2, ARRAY[$q$Day to day, Pipedrive feels lightweight and uncluttered compared to many enterprise CRMs. The drag-and-drop pipeline view is the default screen most users live in, and new team members can typically understand how to log a deal or move it forward within their first session, without extensive training.$q$, $q$Customization is available but kept approachable: admins can add custom fields, create additional pipelines, and build automation rules through a visual workflow builder rather than code. This gives teams meaningful flexibility to adapt the CRM to their sales process without needing developer involvement for routine changes.$q$, $q$Support comes through a combination of in-app guidance, a help center, and a marketplace of third-party apps that extend functionality. The overall experience is oriented toward getting a sales team productive quickly, with an emphasis on visibility into pipeline health over deep, enterprise-grade configurability.$q$]::text[], 4);
